def compute_total_coverage(intervals):
    if not intervals:
        return 0
    intervals.sort(key=lambda x: x[0])  # Sort by start time, not end time
    merged = [intervals[0]]
    for start, end in intervals[1:]:
        last_start, last_end = merged[-1]
        if start <= last_end:
            merged[-1] = [last_start, max(last_end, end)]
        else:
            merged.append([start, end])
    total = 0
    for s, e in merged:
        total += e - s
    return total

